class Solution:
    def lenLongestFibSubseq(self, arr):
        s = set(arr)
        n = len(arr)
        best = 0
        for i in range(n):
            for j in range(i + 1, n):
                x, y = arr[i], arr[j]
                length = 2
                while x + y in s:
                    x, y = y, x + y
                    length += 1
                if length >= 3:
                    best = max(best, length)
        return best

