var lenLongestFibSubseq = function(arr) {
    const idx = new Map();
    arr.forEach((v, i) => idx.set(v, i));
    const n = arr.length;
    const dp = Array.from({ length: n }, () => new Array(n).fill(2));
    let best = 0;
    for (let j = 0; j < n; j++) {
        for (let i = 0; i < j; i++) {
            const prev = arr[j] - arr[i];
            const k = idx.get(prev);
            if (k !== undefined && k < i) {
                dp[i][j] = dp[k][i] + 1;
            }
            if (dp[i][j] > best) best = dp[i][j];
        }
    }
    return best >= 3 ? best : 0;
};
